"""Claude Code Adapter — hooks integration for Aigis.

Generates Claude Code hooks configuration and interceptor scripts
that monitor all tool calls, apply policy rules, and log to the
Activity Stream.

Usage:
    from aigis.adapters.claude_code import install_hooks
    install_hooks(".")  # Install in current project

Or via CLI:
    aig init --agent claude-code
"""

import json
import stat
from pathlib import Path

# Mapping from Claude Code tool names to Aigis action types
TOOL_ACTION_MAP = {
    "Bash": "shell:exec",
    "Read": "file:read",
    "Write": "file:write",
    "Edit": "file:write",
    "Glob": "file:search",
    "Grep": "file:search",
    "WebFetch": "network:fetch",
    "WebSearch": "network:search",
    "Agent": "agent:spawn",
    "NotebookEdit": "file:write",
}

# The interceptor script that runs on every tool call
HOOK_SCRIPT = '''#!/usr/bin/env python3
"""Aigis hook for Claude Code.

Intercepts all tool calls, scans for threats, evaluates policy,
and logs to Activity Stream. Blocks dangerous operations.

Auto-generated by: aig init --agent claude-code
"""
import json
import sys
import os

def main():
    try:
        input_data = json.loads(sys.stdin.read())
    except (json.JSONDecodeError, EOFError):
        print("Aigis: failed to parse hook input — blocking (fail-closed)", file=sys.stderr)
        sys.exit(2)  # Can't parse = block (fail-closed for safety)

    tool_name = input_data.get("tool_name", "")
    tool_input = input_data.get("tool_input", {})
    session_id = input_data.get("session_id", "")
    hook_event = input_data.get("hook_event_name", "")
    cwd = input_data.get("cwd", os.getcwd())

    # Map tool to action
    action = _map_action(tool_name)
    target = _extract_target(tool_name, tool_input)

    try:
        from aigis.activity import ActivityStream, ActivityEvent
        from aigis.policy import load_policy, evaluate
    except ImportError:
        print("Aigis: package not installed — blocking (fail-closed)", file=sys.stderr)
        sys.exit(2)  # Aigis not installed — block (fail-closed)

    # Build event
    event = ActivityEvent(
        action=action,
        target=target,
        agent_type="claude_code",
        session_id=session_id,
        event_type="tool_call",
        cwd=cwd,
        details={
            "tool_name": tool_name,
            "hook_event": hook_event,
        },
    )

    # Scan content for threats (shell commands, file content)
    scannable = _get_scannable_text(tool_name, tool_input)
    if scannable:
        try:
            from aigis import scan
            result = scan(scannable)
            event.risk_score = result.risk_score
            event.risk_level = result.risk_level
            event.matched_rules = [r.rule_id for r in result.matched_rules]
        except Exception as exc:
            print(f"Aigis: scan error ({exc}) — blocking (fail-closed)", file=sys.stderr)
            sys.exit(2)

    # Evaluate policy
    try:
        policy = load_policy()
        decision, rule_id = evaluate(event, policy)
        event.policy_decision = decision
        event.policy_rule_id = rule_id
    except Exception as exc:
        print(f"Aigis: policy error ({exc}) — blocking (fail-closed)", file=sys.stderr)
        decision = "deny"

    # Log to Activity Stream
    try:
        stream = ActivityStream()
        stream.record(event)
    except Exception:
        pass

    # Block if policy denies
    if decision == "deny":
        reason = f"Aigis blocked: {event.policy_rule_id}"
        if event.risk_score > 0:
            reason += f" (risk={event.risk_score})"
        print(reason, file=sys.stderr)
        sys.exit(2)

    # Review = log but allow (in future: queue for human review)
    if decision == "review":
        event.event_type = "policy_review"

    sys.exit(0)


def _map_action(tool_name: str) -> str:
    """Map Claude Code tool name to Aigis action."""
    action_map = {
        "Bash": "shell:exec",
        "Read": "file:read",
        "Write": "file:write",
        "Edit": "file:write",
        "Glob": "file:search",
        "Grep": "file:search",
        "WebFetch": "network:fetch",
        "WebSearch": "network:search",
        "Agent": "agent:spawn",
        "NotebookEdit": "file:write",
    }
    if tool_name.startswith("mcp__"):
        return "mcp:tool_call"
    return action_map.get(tool_name, f"unknown:{tool_name}")


def _extract_target(tool_name: str, tool_input: dict) -> str:
    """Extract the primary target from tool input."""
    if tool_name == "Bash":
        return tool_input.get("command", "")[:500]
    elif tool_name in ("Read", "Write", "Edit"):
        return tool_input.get("file_path", "")
    elif tool_name == "Glob":
        return tool_input.get("pattern", "")
    elif tool_name == "Grep":
        return tool_input.get("pattern", "")
    elif tool_name == "WebFetch":
        return tool_input.get("url", "")
    elif tool_name == "WebSearch":
        return tool_input.get("query", "")
    elif tool_name.startswith("mcp__"):
        return tool_name  # MCP tool name as target
    return str(tool_input)[:200]


def _get_scannable_text(tool_name: str, tool_input: dict) -> str:
    """Extract text content worth scanning from tool input."""
    if tool_name == "Bash":
        return tool_input.get("command", "")
    elif tool_name == "Write":
        return tool_input.get("content", tool_input.get("file_text", ""))[:2000]
    elif tool_name == "Edit":
        return tool_input.get("new_string", "")[:2000]
    elif tool_name == "WebSearch":
        return tool_input.get("query", "")
    return ""


if __name__ == "__main__":
    main()
'''


def generate_hooks_config() -> dict:
    """Generate Claude Code settings.json hooks configuration."""
    hook_cmd = 'python "$CLAUDE_PROJECT_DIR/.claude/hooks/aig-guard.py"'
    return {
        "hooks": {
            "PreToolUse": [
                {
                    "matcher": ".*",
                    "hooks": [
                        {
                            "type": "command",
                            "command": hook_cmd,
                            "timeout": 10,
                        }
                    ],
                }
            ],
        }
    }


def install_hooks(project_dir: str = ".") -> None:
    """Install Aigis hooks into a Claude Code project.

    Creates:
      - .claude/hooks/aig-guard.py (interceptor script)
      - Merges hooks into .claude/settings.json
    """
    project = Path(project_dir)

    # Create hooks directory
    hooks_dir = project / ".claude" / "hooks"
    hooks_dir.mkdir(parents=True, exist_ok=True)

    # Write interceptor script
    script_path = hooks_dir / "aig-guard.py"
    script_path.write_text(HOOK_SCRIPT, encoding="utf-8")
    # Make executable on Unix
    try:
        script_path.chmod(script_path.stat().st_mode | stat.S_IEXEC)
    except Exception:
        pass

    # Merge hooks into settings.json
    settings_path = project / ".claude" / "settings.json"
    existing = {}
    if settings_path.exists():
        try:
            existing = json.loads(settings_path.read_text(encoding="utf-8"))
        except json.JSONDecodeError:
            existing = {}

    hooks_config = generate_hooks_config()

    # Merge hooks (don't overwrite existing hooks)
    if "hooks" not in existing:
        existing["hooks"] = {}
    for event, matchers in hooks_config["hooks"].items():
        if event not in existing["hooks"]:
            existing["hooks"][event] = []
        # Check if Aigis hook already exists
        existing_commands = [
            h.get("command", "") for m in existing["hooks"][event] for h in m.get("hooks", [])
        ]
        if not any("aig-guard" in cmd for cmd in existing_commands):
            existing["hooks"][event].extend(matchers)

    settings_path.write_text(
        json.dumps(existing, indent=2, ensure_ascii=False),
        encoding="utf-8",
    )

    # Warn if hooks are disabled in settings.local.json
    local_settings_path = project / ".claude" / "settings.local.json"
    if local_settings_path.exists():
        try:
            local_data = json.loads(local_settings_path.read_text(encoding="utf-8"))
            if local_data.get("disableAllHooks", False):
                import warnings

                warnings.warn(
                    "disableAllHooks=true in .claude/settings.local.json — "
                    "Aigis hooks will NOT run. "
                    "Set disableAllHooks to false to enable.",
                    stacklevel=2,
                )
        except (json.JSONDecodeError, Exception):
            pass
